CREATE PROCEDURE [dbo].[TR_THONGKE_SANPHAM_GETTOTALBYDATE2]
(
	@tungay DATE,
	@denngay DATE
)
AS
BEGIN
	--DECLARE	@tungay DATE = '2025-01-17'
	--DECLARE	@denngay DATE = '2025-01-17'

	-- BÁO CÁO HIỆN DIỆN
	SELECT A.ngaythang, B.n_op AS nhom,
		SUM(A.songuoi_hanhchanh) AS songuoi,
		0 AS sogio
	INTO #BAOCAO_HIENDIEN
	FROM tr_baocao_hiendien4 A
		INNER JOIN trtb_m_op B ON A.macongdoan = B.c_op
	WHERE B.department IN ('SON', 'DONGGOI')
		AND A.ngaythang BETWEEN @tungay AND @denngay
	GROUP BY A.ngaythang, B.n_op

	-- MÉT VUÔNG SƠN THEO ĐỊNH MỨC
	SELECT masp, SUM(metvuong) AS metvuong
	INTO #DINHMUC_METVUONG
	FROM tr_dinhmuc_son3_metvuong
	WHERE metvuong > 0
	GROUP BY masp;


	SELECT A.ngaythang, D.c_op, D.n_op AS bophan,
		metvuong = SUM(CASE WHEN A.mact = '000' THEN E.metvuong * A.soluong ELSE (A.rong*A.dai*A.soluong)/1000000 END),
		m3_tc = SUM(CASE WHEN A.mact = '000' THEN B.m3_tc * A.soluong ELSE A.sokhoi END),
		cbm = SUM(CASE WHEN A.mact = '000' THEN B.cbm * A.soluong ELSE 0 END), 
		soluong = SUM(A.SOLUONG)
	INTO #THONGKE_SOLUONG
	FROM tr_trangthai_sanxuat A
		INNER JOIN tr_sanpham B ON A.masp1 = B.masp
		INNER JOIN trtb_m_location C ON A.congdoan = C.c_location
		INNER JOIN trtb_m_op D ON C.c_op = D.c_op
		LEFT JOIN #DINHMUC_METVUONG E ON A.MASP = E.masp
	WHERE A.ngaythang BETWEEN @tungay AND @denngay
		AND D.department IN ('SON', 'DONGGOI')
		AND A.congdoan LIKE '%-PROD'
	GROUP BY A.ngaythang, D.c_op, D.n_op

	SELECT B.ngaythang, B.bophan,
		soluong = ISNULL(B.soluong, 0), 
		metvuong = ISNULL(B.metvuong, 0),
		m3_tc = CAST(ISNULL(B.m3_tc, 0) AS decimal(18, 4)),
		cbm = CAST(ISNULL(B.cbm, 0) AS decimal(18, 4)),
		songuoi = ISNULL(A.songuoi, 0), 
		sogio = ISNULL(A.sogio, 0)
	INTO #BAOCAO_TONGHOP
	FROM #BAOCAO_HIENDIEN A
		RIGHT JOIN #THONGKE_SOLUONG B ON A.ngaythang = B.ngaythang AND A.nhom = B.BOPHAN

	DECLARE @HtmlRow TABLE 
	(
		stt int IDENTITY(1,1),
		htmlString nvarchar(max)
	)
	DECLARE @html nvarchar(max);

	IF EXISTS (SELECT 1 FROM #BAOCAO_TONGHOP)
	BEGIN
		SET @html = N'<h2>BẢNG TỔNG HỢP</h2>'
		SET @html = @html + char(13) + char(10) + N'<table border=''1'' cellSpacing=''0'' cellPadding=''2'' style=''width: 1300px; BACKGROUND-COLOR: #ffffff; POSITION: relative; EMPTY-CELLS: show;''>';
		SET @html = @html + char(13) + char(10) + N'<tbody>';

		-- HEADER
		SET @html = @html + char(13) + char(10) + N'<tr>';
		SET @html = @html + char(13) + char(10) + N'<th>Ngày nhập</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Công đoạn</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số lượng</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Mét vuông</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số khối tinh chế</th>';
		SET @html = @html + char(13) + char(10) + N'<th>CBM</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số cont (cbm/68)</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số người</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số giờ</th>';
		SET @html = @html + char(13) + char(10) + N'</tr>';
		INSERT INTO @HtmlRow(htmlString) VALUES (@html);

		DECLARE @NGAYNHAP DATE, @bophan NVARCHAR(200);
		DECLARE @soluong int = 0, @metvuong float = 0, @m3_tc float = 0, @cbm float = 0, @songuoi int = 0, @sogio float = 0;
		DECLARE CUR CURSOR LOCAL FOR
			SELECT ngaythang, bophan, soluong, metvuong, m3_tc, cbm, songuoi, sogio
			FROM #BAOCAO_TONGHOP
			ORDER BY ngaythang, bophan
		OPEN CUR
		FETCH NEXT FROM CUR INTO @NGAYNHAP, @bophan, @soluong, @metvuong, @m3_tc, @cbm, @songuoi, @sogio;
		WHILE @@FETCH_STATUS = 0
		BEGIN
			DECLARE @row nvarchar(max) = '';
			SET @row = @row + char(13) + char(10) + N'<tr>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + FORMAT(@NGAYNHAP, 'dd/MM/yyyy') + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 150px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + @bophan + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@soluong = 0, '&nbsp;', FORMAT(@soluong, 'N00')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@metvuong = 0, '&nbsp;', FORMAT(@metvuong, '#,0.##')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@m3_tc = 0, '&nbsp;', FORMAT(@m3_tc, '#,0.####')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@cbm = 0, '&nbsp;', FORMAT(@cbm, '#,0.####')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@cbm = 0, '&nbsp;', FORMAT(@cbm/68, '#,0.#')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@songuoi = 0, '&nbsp;', FORMAT(@songuoi, 'N00')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + IIF(@sogio = 0, '&nbsp;', FORMAT(@sogio, '#,0.##')) + '</td>';
			SET @row = @row + char(13) + char(10) + N'</tr>';

			INSERT INTO @HtmlRow(htmlString) VALUES (@row);
			FETCH NEXT FROM CUR INTO @NGAYNHAP, @bophan, @soluong, @metvuong, @m3_tc, @cbm, @songuoi, @sogio;
		END
		CLOSE CUR;
		DEALLOCATE CUR;

		SET @html = '';
		SET @html = @html + char(13) + char(10) + N'</tbody>';
		SET @html = @html + char(13) + char(10) + N'</table>';

		INSERT INTO @HtmlRow(htmlString) VALUES (@html);
	END

	SELECT stt, htmlString FROM @HtmlRow ORDER BY stt
	DROP TABLE #BAOCAO_TONGHOP, #THONGKE_SOLUONG, #BAOCAO_HIENDIEN, #DINHMUC_METVUONG;

END

